import re

def normalize_version(raw: str) -> tuple[int, ...]:
    # Remove leading 'v' and any suffix starting with '-'
    cleaned = raw.strip().lstrip('v').split('-')[0]
    parts = [int(p) for p in cleaned.split('.') if p.isdigit()]
    # Pad to 3 components (major, minor, patch)
    while len(parts) < 3:
        parts.append(0)
    return tuple(parts[:3])


def is_compatible(installed: str, required: str) -> bool:
    return normalize_version(installed) >= normalize_version(required)

